import './Table.scss';

import { classNames } from ':helpers/classnames';
import type { CSSProperties, FC } from 'react';
import React from 'react';

import type { TableProps } from './Table.types';

export const Table: FC<TableProps> = ({
	dense = false,
	hover = false,
	alignRight = false,
	horizontalAlign,
	verticalAlign,
	numeric = false,
	monospaceNumeric = false,
	className,
	expandable,
	children,
	scroll,
	...props
}) => {
	const wrapperStyle: CSSProperties = {};
	const tableStyle: CSSProperties = {};

	if (scroll?.x !== undefined) {
		wrapperStyle.overflowX = 'auto';
		const x = scroll.x;
		if (typeof x === 'number') {
			wrapperStyle.width = x;
		} else if (x === true) {
			// Включение горизонтальной прокрутки при переполнении содержимого
			wrapperStyle.width = '100%';
		} else if (typeof x === 'string') {
			if (x === 'max-content') {
				tableStyle.width = 'max-content';
				wrapperStyle.width = '100%';
			} else {
				wrapperStyle.width = x as CSSProperties['width'];
			}
		}
		// Убедитесь, что стол может переполниться горизонтально, когда это необходимо
		if (!tableStyle.width && (typeof scroll.x === 'number' || scroll.x === true)) {
			tableStyle.width = 'max-content';
		}
	}

	if (scroll?.y !== undefined) {
		wrapperStyle.overflowY = 'auto';
		const y = scroll.y;
		if (typeof y === 'number') {
			wrapperStyle.maxHeight = y;
		} else if (typeof y === 'string') {
			wrapperStyle.maxHeight = y as CSSProperties['maxHeight'];
		}
	}

	const { style, ...restProps } = props;

	const tableElement = (
		<table
			data-testid="Table"
			{...restProps}
			style={{ ...style, ...tableStyle }}
			className={classNames(
				'dsb_table',
				dense && 'dsb_table__dense',
				hover && 'dsb_table__hoverable',
				alignRight && 'dsb_table__align-right',
				horizontalAlign && `dsb_table__horizontal-align-${horizontalAlign}`,
				verticalAlign && `dsb_table__vertical-align-${verticalAlign}`,
				expandable && 'dsb_table__expandable',
				numeric && 'dsb_table__align-right',
				monospaceNumeric && 'dsb_table__monospace-numeric',
				className,
			)}
		>
			{children}
		</table>
	);

	if (scroll) {
		return (
			<div className="dsb_table__scroll-wrapper" style={wrapperStyle}>
				{tableElement}
			</div>
		);
	}

	return tableElement;
};
